mapper.select:
select uc.id, uc.coupon_id, uc.user_id, uc.status, uc.obtain_time, uc.use_time, uc.order_id, uc.expire_time, c.name, c.type, c.min_amount, c.discount_value, c.max_discount_amount, c.description, c.user_limit, c.end_time from user_coupon uc left join coupon c on uc.coupon_id = c.id
uc.user_id = #{userId}
and uc.status = #{param2.status}
order by uc.obtain_time desc
